function solve(l_str, r_str, directions) {
    const l = BigInt(l_str);
    const r = BigInt(r_str);

    /**
     * Converts a number x into a 16-digit string representation, padded with leading zeros.
     * @param {BigInt} x
     * @returns {string} 16-character string
