        }

        return sequence;
    };

    /**
     * Checks if the sequence is non-decreasing.
     * @param {number[]} sequence
     * @returns {boolean}
     */
    const isNonDecreasing = (sequence) => {
        for (let i = 0; i < sequence.length - 1; i++) {
            if (sequence[i] > sequence[i + 1]) {
                return false;
            }
        }
        return true;
    };

